-- Hospital Operations Management Database
-- Schema and data (synthesized data; no real patient information)
-- 9 tables: departments, staff, supplies, patients, encounters,
--           referrals, billing_claims, satisfaction_surveys, quality_indicators

-- Table structure for table `billing_claims`
--

DROP TABLE IF EXISTS `billing_claims`;
CREATE TABLE `billing_claims` (
  `ClaimID` int NOT NULL AUTO_INCREMENT,
  `EncounterID` int DEFAULT NULL,
  `BilledAmount` float DEFAULT NULL,
  `AllowedAmount` float DEFAULT NULL,
  `PaidAmount` float DEFAULT NULL,
  `ClaimStatus` varchar(20) DEFAULT NULL,
  `DateSubmitted` date DEFAULT NULL,
  PRIMARY KEY (`ClaimID`),
  KEY `EncounterID` (`EncounterID`),
  CONSTRAINT `billing_claims_ibfk_1` FOREIGN KEY (`EncounterID`) REFERENCES `encounters` (`EncounterID`)
) ENGINE=InnoDB AUTO_INCREMENT=378 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

