DROP TABLE IF EXISTS `encounters`;
CREATE TABLE `encounters` (
  `EncounterID` int NOT NULL AUTO_INCREMENT,
  `PatientID` int DEFAULT NULL,
  `DepartmentID` int DEFAULT NULL,
  `StaffID` int DEFAULT NULL,
  `EncounterType` varchar(20) DEFAULT NULL,
  `EncounterDate` date DEFAULT NULL,
  `DischargeDate` date DEFAULT NULL,
  `ChiefComplaint` varchar(200) DEFAULT NULL,
  `DischargeStatus` varchar(50) DEFAULT NULL,
  `InsuranceType` varchar(50) DEFAULT NULL,
  `BillingCode` varchar(20) DEFAULT NULL,
  `EncounterCost` float DEFAULT NULL,
  `IsReadmission` varchar(3) DEFAULT 'No',
  `LengthOfStayDays` int DEFAULT NULL,
  PRIMARY KEY (`EncounterID`),
  KEY `PatientID` (`PatientID`),
  KEY `DepartmentID` (`DepartmentID`),
  KEY `StaffID` (`StaffID`),
  CONSTRAINT `encounters_ibfk_1` FOREIGN KEY (`PatientID`) REFERENCES `patients` (`PatientID`),
  CONSTRAINT `encounters_ibfk_2` FOREIGN KEY (`DepartmentID`) REFERENCES `departments` (`DepartmentID`),
  CONSTRAINT `encounters_ibfk_3` FOREIGN KEY (`StaffID`) REFERENCES `staff` (`StaffID`)
) ENGINE=InnoDB AUTO_INCREMENT=557 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

