--
-- Table structure for table `satisfaction_surveys`
--

DROP TABLE IF EXISTS `satisfaction_surveys`;
CREATE TABLE `satisfaction_surveys` (
  `SurveyID` int NOT NULL AUTO_INCREMENT,
  `PatientID` int DEFAULT NULL,
  `EncounterID` int DEFAULT NULL,
  `OverallRating` int DEFAULT NULL,
  `StaffRating` int DEFAULT NULL,
  `FacilityRating` int DEFAULT NULL,
  `SurveyDate` date DEFAULT NULL,
  PRIMARY KEY (`SurveyID`),
  KEY `PatientID` (`PatientID`),
  KEY `EncounterID` (`EncounterID`),
  CONSTRAINT `satisfaction_surveys_ibfk_1` FOREIGN KEY (`PatientID`) REFERENCES `patients` (`PatientID`),
  CONSTRAINT `satisfaction_surveys_ibfk_2` FOREIGN KEY (`EncounterID`) REFERENCES `encounters` (`EncounterID`)
) ENGINE=InnoDB AUTO_INCREMENT=269 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

