--
-- Table structure for table `staff`
--

DROP TABLE IF EXISTS `staff`;
CREATE TABLE `staff` (
  `StaffID` int NOT NULL AUTO_INCREMENT,
  `FirstName` varchar(50) DEFAULT NULL,
  `LastName` varchar(50) DEFAULT NULL,
  `Role` varchar(50) DEFAULT NULL,
  `DepartmentID` int DEFAULT NULL,
  `TypicalShift` varchar(20) DEFAULT NULL,
  `HireDate` date DEFAULT NULL,
  `EmploymentStatus` varchar(20) DEFAULT NULL,
  `VaxHBVStatus` varchar(20) DEFAULT NULL,
  `VaxTdapStatus` varchar(20) DEFAULT NULL,
  PRIMARY KEY (`StaffID`),
  KEY `DepartmentID` (`DepartmentID`),
  CONSTRAINT `staff_ibfk_1` FOREIGN KEY (`DepartmentID`) REFERENCES `departments` (`DepartmentID`)
) ENGINE=InnoDB AUTO_INCREMENT=423 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

