--
-- Table structure for table `supplies`
--

DROP TABLE IF EXISTS `supplies`;
CREATE TABLE `supplies` (
  `SupplyID` int NOT NULL AUTO_INCREMENT,
  `SupplyName` varchar(100) DEFAULT NULL,
  `Category` varchar(50) DEFAULT NULL,
  `DepartmentID` int DEFAULT NULL,
  `StockLevel` int DEFAULT NULL,
  `ReorderThreshold` int DEFAULT NULL,
  `ExpirationDate` date DEFAULT NULL,
  `UnitCost` float DEFAULT NULL,
  `UnitOfMeasure` varchar(20) DEFAULT NULL,
  `ControlledItem` tinyint(1) DEFAULT '0',
  `UnitsConsumedLast30Days` int DEFAULT NULL,
  `LastUsageUpdate` date DEFAULT NULL,
  PRIMARY KEY (`SupplyID`),
  UNIQUE KEY `uq_supplies_department_item` (`DepartmentID`,`SupplyName`),
  CONSTRAINT `supplies_ibfk_1` FOREIGN KEY (`DepartmentID`) REFERENCES `departments` (`DepartmentID`)
) ENGINE=InnoDB AUTO_INCREMENT=512 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

